function filterBySearchQuery(e){var t=document.getElementById("topbaicProductsGrid");if(t&&"function"==typeof getProducts){var n=e.toLowerCase(),r="undefined"!=typeof currentLanguage?currentLanguage:"en";getProducts().then(function(o){var a=o.filter(function(e){return(e.name_en||"").toLowerCase().includes(n)||(e.name_ar||"").toLowerCase().includes(n)});if(0===a.length)t.innerHTML='<p style="text-align:center;padding:3rem;color:#999;" data-en="No products found for &quot;'+e+'&quot;" data-ar="لا توجد منتجات لـ &quot;'+e+'&quot;">No products found for &quot;'+e+"&quot;</p>";else{var u=window.TopBaic&&window.TopBaic.createProductCard?window.TopBaic.createProductCard:"function"==typeof createTopBaicProductCard?createTopBaicProductCard:null;if(!u)return;t.innerHTML=a.map(function(e){return u(e)}).join("")}"function"==typeof switchLanguage&&switchLanguage(r);var c=document.getElementById("productCount");c&&(c.innerHTML='<span data-en="Found '+a.length+" results for &quot;"+e+'&quot;" data-ar="تم العثور على '+a.length+' نتيجة">Found '+a.length+" results for &quot;"+e+"&quot;</span>")}).catch(function(e){console.error("filterBySearchQuery error:",e)})}}document.addEventListener("DOMContentLoaded",function(){var e=new URLSearchParams(window.location.search).get("search");if(e){var t=document.getElementById("primejoSearchInput");t&&(t.value=e,t.dispatchEvent(new Event("input")));var n=0,r=setInterval(function(){var t=document.getElementById("topbaicProductsGrid");++n>20?clearInterval(r):t&&t.children.length>0&&!t.querySelector("p")&&(clearInterval(r),filterBySearchQuery(e))},100)}});